arguments.file_text:
@inject ISettingsService SettingsService

<h4 class="mb-4">Profile Settings</h4>

@if (_loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_profile is not null)
{
    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="row mb-4">
        <div class="col-md-3 text-center">
            <div class="border rounded p-3">
                @if (!string.IsNullOrEmpty(_avatarUrl))
                {
                    <img src="@_avatarUrl" alt="Avatar" class="rounded-circle mb-2" style="width:100px;height:100px;object-fit:cover;" />
                }
                else
                {
                    <div class="bg-secondary rounded-circle d-inline-flex align-items-center justify-content-center mb-2"
