                    <p class="text-muted small">This will sign out that device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public bool Visible { get; set; }

    [Parameter]
    public ActiveSession? Session { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnConfirmed { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnCancelled { get; set; }

    private async Task Confirm() => await OnConfirmed.InvokeAsync();
    private async Task Cancel() => await OnCancelled.InvokeAsync();
}

@inject ISettingsService SettingsService

<h4 class="mb-4">Security Settings</h4>

@if (_loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_settings is not null)
{
    <ChangePasswordPanel OnChangePassword="HandleChangePasswordAsync" />

    <div class="card my-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <p class="text-muted small mb-0">
                        @if (_settings.TwoFactorEnabled)
                        {
                            <span class="badge bg-success me-1">Enabled</span>
                            <span>Your account is protected with 2FA.</span>
                        }
                        else
                        {
                            <span class="badge bg-warning text-dark me-1">Disabled</span>
                            <span>Enable 2FA for extra security.</span>
                        }
                    </p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_settings.TwoFactorEnabled" disabled />
                </div>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h6 class="mb-0">Active Sessions</h6>
            <span class="badge bg-primary">@_settings.Sessions.Count</span>
        </div>
        <div class="card-body p-0">
            @if (_settings.Sessions.Count == 0)
            {
                <p class="text-muted p-3">No active sessions.</p>
            }
            else
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _settings.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td>
                                        @if (session != _settings.Sessions.First())
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => ShowRevokeDialog(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
        </div>
    </div>

    @if (_settings.LastPasswordChange.HasValue)
    {
        <p class="text-muted small">
            Last password change: @_settings.LastPasswordChange.Value.ToString("f")
        </p>
    }

    <RevokeSessionDialog Visible="_showRevokeDialog"
                         Session="_sessionToRevoke"
                         OnConfirmed="ConfirmRevokeAsync"
                         OnCancelled="CancelRevoke" />
}

@code {
    private SecuritySettings? _settings;
    private bool _loading = true;
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadSettingsAsync();
    }

    private async Task LoadSettingsAsync()
    {
        _loading = true;
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _loading = false;
    }

    private async Task HandleChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        await LoadSettingsAsync();
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _showRevokeDialog = false;
            _sessionToRevoke = null;
            await LoadSettingsAsync();
        }
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

