@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance Settings</h4>

@if (_loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    @if (_successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_successMessage
            <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                                   value="@theme" checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                                   value="@size" checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title">Language</h6>
                    <select class="form-select" @bind="_language">
                        <option value="en">English</option>
                        <option value="es">Español</option>
                        <option value="fr">Français</option>
                        <option value="de">Deutsch</option>
                        <option value="ja">日本語</option>
                        <option value="zh">中文</option>
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-5">
            <div class="card sticky-top" style="top:1rem">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body @PreviewBackgroundClass" style="@PreviewStyle">
                    <h5 class="@PreviewTextClass">Sample Heading</h5>
                    <p class="@PreviewTextClass" style="@PreviewFontStyle">
                        This is how your content will look with the selected settings.
                        The quick brown fox jumps over the lazy dog.
                    </p>
                    <div class="d-flex gap-2 @(_compactMode ? "mt-1" : "mt-3")">
                        <button class="btn @PreviewButtonClass @(_compactMode ? "btn-sm" : "")">Primary</button>
                        <button class="btn btn-outline-secondary @(_compactMode ? "btn-sm" : "")">Secondary</button>
                    </div>
                    <div class="@(_compactMode ? "mt-2" : "mt-3")">
                        <span class="badge @PreviewBadgeClass me-1">Tag 1</span>
                        <span class="badge @PreviewBadgeClass me-1">Tag 2</span>
                        <span class="badge @PreviewBadgeClass">Tag 3</span>
                    </div>
                    <p class="text-muted small @(_compactMode ? "mt-1 mb-0" : "mt-3 mb-0")">
                        Theme: @_theme · Font: @_fontSize · Language: @GetLanguageName() · Compact: @(_compactMode ? "On" : "Off")
                    </p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string _theme = "Light", _fontSize = "Medium", _language = "en";
    private bool _compactMode;
    private bool _loading = true, _saving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        _successMessage = "Appearance settings saved!";
        _saving = false;
    }

    private string PreviewBackgroundClass => _theme switch
    {
        "Dark" => "bg-dark",
        _ => "bg-light"
    };

    private string PreviewTextClass => _theme switch
    {
        "Dark" => "text-light",
        _ => "text-dark"
    };

    private string PreviewButtonClass => _theme switch
    {
        "Dark" => "btn-light",
        _ => "btn-primary"
    };

    private string PreviewBadgeClass => _theme switch
    {
        "Dark" => "bg-light text-dark",
        _ => "bg-primary"
    };

    private string PreviewStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
